import os
defaults = {"timeout": 30, "retries": 1}
file_cfg = {"timeout": 10}
env = {"TIMEOUT": "5"}
flags = {"timeout": 3}
# flags > env > file > defaults
cfg = {**defaults, **file_cfg}
if "TIMEOUT" in env:
    cfg["timeout"] = int(env["TIMEOUT"])
cfg.update({k: v for k, v in flags.items() if v is not None})
print(cfg)

